### 3. Tool Badge Overflow Handling
When there are many tool calls (e.g., 10+), show first N badges plus "+X more":

```rust
const MAX_VISIBLE_BADGES: usize = 6;

fn render_tool_badges(
    tools: &[ToolCallWithResult],
    options: &RenderOptions,
) -> (String, usize) {
    if tools.len() <= MAX_VISIBLE_BADGES {
        // Render all
        let badges = tools.iter().map(render_single_badge).collect::<Vec<_>>().join("");
        (badges, 0)
    } else {
        // Render first N + overflow badge
        let visible: String = tools[..MAX_VISIBLE_BADGES]
            .iter()
            .map(render_single_badge)
            .collect();
        let overflow = tools.len() - MAX_VISIBLE_BADGES;
        let overflow_badge = format!(
            r#"<span class="tool-badge tool-overflow" aria-label="{} more tools">+{}</span>"#,
            overflow, overflow
        );
        (format!("{}{}", visible, overflow_badge), overflow)
    }
}
```

